import{_ as a,o as t,c as n,O as r}from"./chunks/framework.92cbe775.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/index.md","filePath":"en/product/index.md","lastUpdated":1776137300000}'),s={name:"en/product/index.md"};function i(l,e,o,d,c,p){return t(),n("div",null,e[0]||(e[0]=[r('<div class="brand-page-shell"><section class="brand-hero brand-hero--product"><div><p class="brand-kicker">Product Overview</p><h1>Product Overview</h1><div class="brand-hero__panel"><span class="brand-pill">Product Signal</span><strong>ExecFabric is aimed at automation execution and governance for real tasks. Right now it is better understood from script governance, file handling, and local automation flows that can already land.</strong><p>Separate what is already done, what is still being pushed, and what may expand later. That is how the product avoids rework.</p></div><p class="brand-lead"><strong>The current best way to understand ExecFabric is this: it first turns Python and Shell scripts, file handling, and local automation flows into one unified entry so execution, confirmation, and result return are all traceable.</strong></p><p class="brand-lead"><strong>Under the surface, ExecFabric is still a multi-tenant governance and execution foundation that treats Python scripts as the first mature execution asset.</strong></p><p class="brand-lead"> Starting with Python scripts does not mean the scope is small. It means Python is the most common, most real, and easiest place to form a deliverable, reusable, expandable small closed loop first. </p><p> The most mature execution asset today is still the Python script, but the long-term object under platform management is a standardized, schedulable, auditable capability unit rather than just one type of script file. </p><p> This is no longer only a concept story. The platform has already completed its first compatibility-oriented upgrade: it now has a general resource layer and an executor registry layer, and the first non-script capability sample, <code>HTTP capability access</code>, has already landed inside the <code>public</code> super-admin domain. Tenant-side users also already have a read-only ledger where they can see the summary of the HTTP resources they are currently authorized to view, the authentication style, and the write boundary. That still does not mean tenant-side self-service onboarding of multiple capability types is fully open, and it definitely does not mean the product has already become a generic API platform. Configuration, credential governance, and dry-run for this type of resource still stay inside the <code>public</code> governance domain. </p><p> This round also tightened the security boundary further: whitelisted tenant admins keep only a minimal cross-tenant console entry, and do not directly see platform-governance pages such as <code>HTTP capability access</code>. Menus, permissions, and runtime checks also no longer rely on unsafe conditions such as <code>user_id == 1</code> to infer administrator status. </p><p> At the same time, the first segment of the <code>1.1</code> lower-support loop has already landed: the <code>public</code> order center already supports order creation, payment confirmation, activation execution, renewal-reminder scans, and expiry-shutdown scans. The personal free frontend already has the first version of the local script-slot billing center, where users can see the current order, lifecycle summary, reconciliation summary, recent callbacks, and the checkout entry. Real third-party payment gateways, auto-renewal or auto-charge, and outbound reminder channels are still being filled in. </p><p> At the same time, the shared-SaaS tenant frontend skeleton has already been built: from <code>tenant_1003+</code> onward, standard SaaS customers no longer default to cloning one new frontend project per customer. They first go through the shared tenant frontend instead. It can already carry the formal tenant entry, but branding, initialization, and finer menu boundaries are still being tightened. </p><div class="brand-chip-list"><span class="brand-chip">multi-tenant governance</span><span class="brand-chip">trusted execution</span><span class="brand-chip">free-path entry</span><span class="brand-chip">CLI / Agent path</span><span class="brand-chip">HTTP sample landed</span><span class="brand-chip">shared SaaS</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../guide/getting-started.html">Try it for free now</a><a class="cta-button" href="./scenarios.html">View scenarios</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // PRODUCT SIGNAL</span><span>DOC 01</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">corePosition</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;controlled_ai_execution_platform&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">userPath</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;free_entry&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;local_slots&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;team_saas&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;enterprise_delivery&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">executionSurface</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;web_console&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;cli_bridge&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;local_env&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">REAL EXECUTION / CLEAR POSITIONING</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">status</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">current</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span><span class="matrix-panel__op"> + </span><span class="matrix-panel__value">product</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">docs</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public</span></span></div></div><div class="product-signal-grid"><article class="brand-hero__panel product-signal-card"><span class="link-panel-label">Current Asset</span><strong>Stabilize script-shaped capability first</strong><p>Stabilize onboarding, execution, audit, and delivery on the main chain first, then gradually expand into more capability forms.</p></article><article class="brand-hero__panel product-signal-card"><span class="link-panel-label">Near Term</span><strong>Stabilize the one line that can really land first</strong><p>The free experience, tenant governance, and formal delivery already share one foundation. That keeps later expansion from turning into rework.</p></article><article class="brand-hero__panel product-signal-card product-signal-card--wide"><span class="link-panel-label">What You Can Verify Now</span><strong>What is verifiable today is more than a demo page</strong><p>If you are trying to judge whether the platform is still only conceptual, start with the five points below. They correspond to chains that already landed or are already in real use, not distant imagination.</p><div class="product-signal-checks"><div class="product-signal-check"><span>Public entry</span><strong>Run one real execution chain from the no-login experience page first</strong></div><div class="product-signal-check"><span>Mature asset</span><strong>Python scripts are already the first onboardable and auditable execution asset</strong></div><div class="product-signal-check"><span>Governance sample</span><strong>HTTP capability access already landed inside the <code>public</code> governance domain</strong></div><div class="product-signal-check"><span>Lifecycle</span><strong>The first segment of the <code>1.1</code> order, activation, renewal, and shutdown skeleton has landed</strong></div><div class="product-signal-check"><span>Standard team path</span><strong>The shared-SaaS tenant frontend already exists and no longer defaults to cloning one new frontend per customer</strong></div></div></article></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">How To Read It</p><h2>How this product should be understood in the current stage</h2><ul class="brand-list"><li>Start with how it turns scripts, file handling, and local flows into a unified entry.</li><li>Start with the execution, audit, permission boundary, and result-return chains that have already landed.</li><li>Then move into how it expands toward team collaboration, shared SaaS, and private delivery.</li><li>Judge fit through a real scenario first, then decide the implementation path and edition choice.</li></ul></article><article class="brand-card"><p class="brand-kicker">What To Watch</p><h2>Do not skip these boundaries during evaluation</h2><ul class="brand-list"><li>Do not treat payment and the full SaaS self-serve loop as fully mature when they are still being filled in.</li><li>Do not ignore the fact that the HTTP capability sample still mainly stays inside the <code>public</code> governance domain.</li><li>Do not mix shared SaaS, single-tenant delivery, and private deployment into one delivery mode.</li><li>Do not stay only at the concept layer. It is better to judge fit through a real scenario.</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Platform</p><h2>Platform position</h2><ul class="brand-list"><li>Under the surface, ExecFabric is a multi-tenant governance and execution foundation that treats Python scripts as the first mature execution asset.</li><li>Externally, it is currently better to enter from script governance, file handling, and local automation flows that can already land.</li><li>The most mature capability shape today is script-shaped onboarding, execution, audit, and continuous update.</li><li>The platform already has a general resource layer and executor registry layer. The first non-script sample is HTTP capability access in the <code>public</code> super-admin domain, and tenant-side users already have a read-only ledger.</li><li>HTTP resources currently move only through &quot;fixed interfaces, explicit authentication, and write whitelists.&quot; Configuration authority remains on the <code>public</code> side, and this is not being packaged as a generic API platform.</li><li>The first segment of the <code>1.1</code> order and lifecycle skeleton already exists on the <code>public</code> side, and the personal free frontend already has a real first-version billing center. That still does not mean the product publicly promises a complete general subscription or auto-renewal capability.</li><li>From <code>tenant_1003+</code> onward, standard SaaS customers currently go through the shared tenant frontend first. Stronger isolation or deeper customization can still move into single-tenant delivery or private deployment later.</li><li><code>execfabric-shell</code> is mainly used for multi-entry aggregation, joint debugging, and sync. It is not the long-term formal runtime entry for customers.</li><li>The platform may later expand into APIs, templates, connectors, approval flows, and other capability types, but only step by step under real demand.</li></ul></section><section class="brand-card"><p class="brand-kicker">Current Paths</p><h2>The four external paths that are currently the most stable</h2><table><thead><tr><th>Layer</th><th>Best for</th><th>How to understand it today</th><th>Suggested entry</th></tr></thead><tbody><tr><td>Free path</td><td>People touching the platform for the first time</td><td>Feel the product position, execution chain, and personal-entry value first</td><td><a href="../guide/getting-started.html">Getting Started</a></td></tr><tr><td>Local script-slot expansion</td><td>People already continuing to connect scripts in personal space</td><td>This is personal-space expansion, not a formal team subscription</td><td><a href="./personal-billing-membership.html">Billing &amp; Membership</a></td></tr><tr><td>Standard team edition</td><td>Teams entering multi-user collaboration</td><td>Currently carried by the shared-SaaS formal tenant entry instead of cloning a new frontend project by default</td><td><a href="./customer-flow.html">Customer Flow / Delivery</a></td></tr><tr><td>Enterprise delivery</td><td>Customers that need stronger isolation, intranet access, or formal project acceptance</td><td>Continue through single-tenant delivery, private deployment, or deeper deployment control</td><td><a href="./deployment.html">Deployment</a></td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Brand</p><h2>Brand wording</h2><ul class="brand-list"><li>Brand name: <code>ExecFabric</code></li><li>Subtitle: a multi-tenant governance and execution system for real-world tasks</li><li>Slogan: make every automation reliable and governed.</li><li>This framing is suitable for product introduction, scenario communication, and current delivery explanation.</li></ul></article><article class="brand-card"><p class="brand-kicker">Method</p><h2>Current usage principles</h2><ul class="brand-list"><li>Use <code>ExecFabric</code> externally as one unified brand rather than splitting into separate English and Chinese product naming tracks.</li><li>Governance first, execution second. Stabilize script-shaped capability first, then gradually expand into more capability types.</li><li>The repository slug and directory path <code>execfabric-cli/</code> stay in place for now, while the external command is already unified as <code>execfabric-cli</code>, so the current engineering and release chain is not disrupted.</li><li>This keeps brand cognition unified without interrupting the current code, docs, and delivery rhythm.</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Not Building</p><h2>What the platform is not trying to become right now</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>Not a free-form chat system</h3><p>The point is not just to expose a model. The point is to let real tasks execute stably under rules.</p></article><article class="brand-card brand-card--nested"><h3>Not a trimmed enterprise admin panel</h3><p>The free edition is not simply a complex backend menu made public. It is meant to be an independent, lighter, formal entry with room to grow.</p></article><article class="brand-card brand-card--nested"><h3>Not a demo-script assembly site</h3><p>It has to carry real delivery, platform governance, and continuous maintenance rather than a temporary collection of scripts.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Core Problems</p><h2>What the platform is solving right now</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><span class="brand-pill">01</span><h3>Isolation for formal customers</h3><p>Different customers, teams, and environments cannot be mixed together. They need an execution platform that can isolate, govern, and keep delivering over time.</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">02</span><h3>Trusted AI execution</h3><p>AI must not only answer. It has to execute real tasks under confirmation and rule constraints instead of calling scripts with uncontrolled privilege.</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">03</span><h3>Product entry continuity</h3><p>The personal free path, formal team collaboration, and enterprise delivery need one continuous journey rather than three disconnected systems.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Future Asset Types</p><h2>Which capability types are likely to be added next</h2><p>The directions below show where the platform is likely to expand next. They describe the expansion boundary, not a promise that every item is already fully commercialized.</p><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>API / SaaS calls</h3><p>Turn third-party services, internal enterprise interfaces, and webhooks into governed capability entries. The first sample already exists as HTTP capability access in the <code>public</code> governance domain.</p></article><article class="brand-card brand-card--nested"><h3>Data connectors</h3><p>Turn database queries, warehouse writes, and CRM or ERP read-write operations into standardized capability units.</p></article><article class="brand-card brand-card--nested"><h3>Document-template services</h3><p>Bring contracts, reports, weekly summaries, and standard document-generation flows into one unified execution entry.</p></article><article class="brand-card brand-card--nested"><h3>Approval / workflow triggers</h3><p>Turn leave requests, procurement, tickets, and status transitions into auditable capability actions.</p></article><article class="brand-card brand-card--nested"><h3>Specialized model services</h3><p>Bring OCR, document parsing, speech recognition, image generation, and other model capabilities into the same governance chain.</p></article><article class="brand-card brand-card--nested"><h3>Ops and notification actions</h3><p>Continue bringing inspection, alerting, log cleanup, backup, and outbound notifications into the trusted-execution range.</p></article></div></section><section class="brand-card"><p class="brand-kicker">How To Start</p><h2>Where different roles should start</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Individual explorers</h3><ul class="brand-list"><li>Start from the no-login experience page and feel one real execution chain quickly.</li><li>After signup, users first go through the separate result page and then enter the personal path. The current valid menu set continues through My Skill Library, Script Upload, Intelligent Assistant, Execution History, Personal Space, Announcement Center, Community Plaza, and Upgrade to Formal Version, while keeping extension entries such as the HTTP read-only ledger.</li><li>If the goal is still individual continuous usage, prioritize lightweight local script-slot expansion instead of jumping straight into enterprise-delivery framing.</li><li>This is the right place to verify whether AI can really schedule scripts for me.</li></ul></article><article class="brand-card brand-card--nested"><h3>Teams and enterprises</h3><ul class="brand-list"><li>If the need is standard capability and lighter collaboration, evaluate the shared-SaaS shared-tenant path first.</li><li>If the focus is standard team collaboration, start with the formal team-edition tenant entry instead of jumping directly into an enterprise project.</li><li>If the need involves multi-user collaboration, permission control, audit, or local onboarding, continue the conversation around scenario and delivery boundaries.</li><li>If intranet, compliance, or private deployment is involved, continue into the enterprise plan discussion.</li><li>Clarifying the business scenario first is more effective than comparing feature tables first.</li></ul></article></div></section><section class="brand-card"><p class="brand-kicker">Priority Customers</p><h2>The three customer groups that fit best today</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>E-commerce, content, and operations-data automation teams</h3><p>These teams usually already have many scattered scripts, spreadsheets, and data-processing flows. They are the easiest fit for the Python-script path and the fastest to feel the value of one unified entry plus execution traces.</p></article><article class="brand-card brand-card--nested"><h3>Technical teams doing script governance and automation ops</h3><p>These teams are better prepared to accept CLI, local execution, permission boundaries, and audit trails, which matches the platform&#39;s most mature current capabilities.</p></article><article class="brand-card brand-card--nested"><h3>Small formal customers that need intranet access or private deployment</h3><p>These customers validate multi-tenant isolation, super-admin governance, and the formal delivery chain most clearly, but customization depth still has to be controlled so only platform-strengthening projects are taken.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>Public documentation reading path</h2><div class="brand-link-grid"><a class="brand-link-card" href="./scenarios.html"><span>Step 01</span><strong>Scenarios</strong><p>Start from the real business scenarios this platform solves instead of memorizing module names first.</p></a><a class="brand-link-card" href="./capabilities.html"><span>Step 02</span><strong>Capabilities</strong><p>Then see how multi-tenancy, trusted execution, template distribution, announcement governance, and the CLI bridge form one closed loop.</p></a><a class="brand-link-card" href="./customer-flow.html"><span>Step 03</span><strong>Customer Flow / Delivery</strong><p>Look directly at how customers use it, how delivery works, and how script hot updates currently close the loop.</p></a><a class="brand-link-card" href="./personal-billing-membership.html"><span>Step 04</span><strong>Billing &amp; Membership</strong><p>See separately how the personal free page handles payment, how monthly or annual team registration works, and how complete the payment line really is today.</p></a><a class="brand-link-card" href="./architecture.html"><span>Step 05</span><strong>Architecture</strong><p>Understand how the backend, super-admin domain, free edition, delivery frontend, and local onboarding fit together.</p></a><a class="brand-link-card" href="./cli.html"><span>Step 06</span><strong>CLI Guide</strong><p>Look directly at the current landed boundary of <code>login / register / list / run / agent</code>.</p></a><a class="brand-link-card" href="./deployment.html"><span>Step 07</span><strong>Deployment</strong><p>See how the platform covers shared SaaS, single-tenant delivery, platform governance, the free public entry, and local hybrid execution.</p></a><a class="brand-link-card" href="./editions.html"><span>Step 08</span><strong>Current Stage</strong><p>Finish by looking at what <code>1.0</code> is doing now, what the next priorities are, and why the roadmap is intentionally not stretched too far yet.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Delivery Extension</p><h2>When moving from experience to formal onboarding, add these three pages next</h2><div class="brand-link-grid brand-link-grid--three"><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong><p>Best for file-driven tasks, report artifacts, and scenarios that need batch-state visibility. Start by making the input-file and result-file chain explicit.</p></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>Deliverables</strong><p>Best for formal delivery discussion, where the customer needs to know which entry points, instructions, and result artifacts will actually be handed over.</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong><p>Best for aligning script directories, README files, sample files, dependencies, and risk boundaries together with presales, implementation, and the customer.</p></a></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why ExecFabric</p><h2>The project value of this kind of platform</h2><ul class="brand-list"><li>The point is not to expose a model and stop there. The point is to make AI execute inside rules.</li><li>The point is not a one-time demo. The point is a system that can keep accumulating capability assets, processes, and audit records.</li><li>The personal free path, formal delivery, and local onboarding can all share the same trusted-execution foundation.</li><li>The platform supports a web entry, local script onboarding, and a broader capability-bridging path that can continue later.</li></ul></article><article class="brand-card"><p class="brand-kicker">Good Fit</p><h2>Who it fits today</h2><ul class="brand-list"><li>E-commerce, content, and operations-data automation teams</li><li>Technical teams that need script governance and automation operations</li><li>Smaller formal customers that need intranet deployment, private deployment, or stricter security boundaries</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>Continue into product detail, or move directly into four-path lead routing</h2><p class="brand-lead">Continue with scenarios, CLI onboarding, and capabilities, or submit a lead directly to decide whether to stay on the free path, expand local script slots, move into the standard team edition, or enter enterprise delivery.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./scenarios.html"><span>Scenario</span><strong>Scenarios</strong></a><a class="brand-link-card" href="./cli.html"><span>CLI</span><strong>CLI Guide</strong></a><a class="brand-link-card" href="./customer-flow.html"><span>Delivery</span><strong>Customer Flow / Delivery</strong></a><a class="brand-link-card" href="./personal-billing-membership.html"><span>Billing</span><strong>Billing &amp; Membership</strong></a><a class="brand-link-card" href="./capabilities.html"><span>Capability</span><strong>Capabilities</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>Submit a lead / routing</strong></a></div></div></section></div>',1)]))}const m=a(s,[["render",i]]);export{u as __pageData,m as default};
